import{_ as e,o as d,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const i="/images/lekt5301.jpg",a="/images/lekt5302.jpg",o="/images/lekt5305.jpg",u="/images/lekt5306.jpg",l="/images/lekt5307.jpg",s="/images/lekt5308.jpg",m="/images/lekt5309.jpg",p="/images/lekt5303.jpg",b="/images/lekt5304.jpg",z=JSON.parse('{"title":"Lektion 53 (Semesterferien)","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion53.md","filePath":"lektionen/lektion53.md"}'),h={name:"lektionen/lektion53.md"};function c(q,t,k,g,f,v){return d(),r("div",null,[...t[0]||(t[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-53-semesterferien" tabindex="-1">Lektion 53 (Semesterferien) <a class="header-anchor" href="#lektion-53-semesterferien" aria-label="Permalink to &quot;Lektion 53 (Semesterferien)&quot;">​</a></h1><h2 id="lektion-53-semesterferien-1" tabindex="-1">Lektion 53 (Semesterferien) <a class="header-anchor" href="#lektion-53-semesterferien-1" aria-label="Permalink to &quot;Lektion 53 (Semesterferien)&quot;">​</a></h2><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>53.1. Der Dual (द्विवचन n.) der Nomina</li><li>53.2. Dualendungen des Nomen</li><li>53.3. Der Dual konsonantisch auslautender Stämme <ul><li>53.3.1. Stämme ohne Stammabstufung</li><li>53.3.2. Stämme mit Stammabstufung</li></ul></li><li>53.4. Der Dual vokalisch auslautender Stämme</li><li>53.5. Dualdvandva</li><li>53.6. Der Dual von Pronomina</li><li>53.7. Pronominaladjektive</li><li>53.8. Unregelmäßige Steigerung</li><li>53.9. Deklination der Komparative auf -īyas</li><li>53.10. Metrik (Lehre von den Versmaßen) <ul><li>53.10.1. Bedeutung der Bestimmung des Metrums</li><li>53.10.2. Arten von Metren</li><li>53.10.3. Die metrische Quantität von Silben</li><li>53.10.4. Der epische Śloka (श्लोक m.)</li></ul></li><li>53.11. Übung</li></ul><h2 id="_53-1-der-dual-द्विवचन-n-der-nomina" tabindex="-1">53.1. Der Dual (द्विवचन n.) der Nomina <a class="header-anchor" href="#_53-1-der-dual-द्विवचन-n-der-nomina" aria-label="Permalink to &quot;53.1. Der Dual (द्विवचन n.) der Nomina&quot;">​</a></h2><p>Der Dual (द्विवचनम्) wird verwendet, um &quot;zwei&quot; zu bezeichnen:</p><blockquote><p>अश्विनौ &quot;die beiden Aśvin&quot;</p></blockquote><p>Die Verwendung des Dual ist dort obligatorisch, wo es sich um zwei Dinge usw. handelt:</p><blockquote><p>हस्तौ &quot;die Hände (eines Individuums)&quot;<br> पादौ &quot;die Füße (eines Menschen, Affen oder sonstigen Zweifüßers)&quot;</p></blockquote><p>Manchmal bezeichnet der Dual ein männliches plus ein weibliches Exemplar derselben Klasse (Art, Gattung):</p><blockquote><p>पितरौ &quot;Vater und Mutter = Eltern&quot;</p></blockquote><p>Wörter, die &quot;ein Paar&quot; bedeuten - z.B. युग n., द्वन्द्व n., द्वय n. - werden aber immer im Singular verwendet, es sei denn es handle sich um zwei oder mehr Paare:</p><blockquote><p>बाहुद्वयम् &quot;ein Paar Arme&quot;</p></blockquote><p><img src="'+i+'" alt=""><br> Abb.: मार्जारयुगम् :  गुम्पिदैक्षेर्लावावयोर्मार्जारौ = &quot;Ein Katzenpaar: Gumpi und Deixerl, die beiden Katzen (मार्जार m.) von uns beiden&quot;<br> (Bild: Payer)</p><p><img src="'+a+'" alt=""><br> Abb.: हस्तौ<br> पुणे<br> [Bildquelle: zen. -- <a href="http://www.flickr.com/photos/zen/384505854/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/zen/384505854/</a>. -- Zugriff am 2009-01-18. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)</p><h2 id="_53-2-dualendungen-des-nomen" tabindex="-1">53.2. Dualendungen des Nomen <a class="header-anchor" href="#_53-2-dualendungen-des-nomen" aria-label="Permalink to &quot;53.2. Dualendungen des Nomen&quot;">​</a></h2><p>|   | Maskulininum/Femininum<br> पुंस्/स्त्री | Neutrum<br> नपुंसक | | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | -au | -ī | | तृतीया, चतुर्थी, पञ्चमी | -bhyām | | सष्ठी, सप्तमी | -os |</p><p>Bei Nomina mit Stammabstufung haben der Nom.Akk.Vok.Dual m.f. den starken Stamm</p><h2 id="_53-3-der-dual-konsonantisch-auslautender-stamme" tabindex="-1">53.3. Der Dual konsonantisch auslautender Stämme <a class="header-anchor" href="#_53-3-der-dual-konsonantisch-auslautender-stamme" aria-label="Permalink to &quot;53.3. Der Dual konsonantisch auslautender Stämme&quot;">​</a></h2><h3 id="_53-3-1-stamme-ohne-stammabstufung" tabindex="-1">53.3.1. Stämme ohne Stammabstufung <a class="header-anchor" href="#_53-3-1-stamme-ohne-stammabstufung" aria-label="Permalink to &quot;53.3.1. Stämme ohne Stammabstufung&quot;">​</a></h3><p>सत्यवाच् 3 &quot;die Wahrheit sprechend&quot;</p><blockquote><p>|   | Maskulininum/Femininum<br> पुंस्/स्त्री | Neutrum<br> नपुंसक | | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | सत्यवाचौ | सत्यवाची | | तृतीया, चतुर्थी, पञ्चमी | सत्यवाग्भ्याम् | | सष्ठी, सप्तमी | सत्यवाचोस् |</p></blockquote><p>बलिन् 3 &quot;(besonders) stark&quot;</p><blockquote><p>|   | Maskulininum<br> पुंस् | Neutrum<br> नपुंसक | | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | बलिनौ | बलिनी | | तृतीया, चतुर्थी, पञ्चमी | बलिभ्याम् | | सष्ठी, सप्तमी | बलिनोस् |</p></blockquote><p>सुमनस् 3 &quot;wohlgesinnt&quot;</p><blockquote><p>|   | Maskulininum/Femininum<br> पुंस्/स्त्री | Neutrum<br> नपुंसक | | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | सुमनसौ | सुमनसी | | तृतीया, चतुर्थी, पञ्चमी | सुमनोभ्याम् | | सष्ठी, सप्तमी | सुमनसोस् |</p></blockquote><p>हविस् n. &quot;Opfergabe&quot;</p><blockquote><p>|   | Neutrum<br> नपुंसक | | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | हविषी | | तृतीया, चतुर्थी, पञ्चमी | हविर्भ्याम् | | सष्ठी, सप्तमी | हविषोस् |</p></blockquote><p>दीर्धायुस् 3 &quot;langlebig&quot;</p><blockquote><p>|   | Maskulininum/Femininum<br> पुंस्/स्त्री | Neutrum<br> नपुंसक | | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | दीर्घायुषौ | दीर्घायुषी | | तृतीया, चतुर्थी, पञ्चमी | दीर्घायुर्भ्याम् | | सष्ठी, सप्तमी | दीर्घायुषोस् |</p></blockquote><h3 id="_53-3-2-stamme-mit-stammabstufung" tabindex="-1">53.3.2. Stämme mit Stammabstufung <a class="header-anchor" href="#_53-3-2-stamme-mit-stammabstufung" aria-label="Permalink to &quot;53.3.2. Stämme mit Stammabstufung&quot;">​</a></h3><p>Partizip Präsens Parasmaipada</p><p>भरन्त् 3 &quot;tragend&quot;</p><blockquote><p>|   | Maskulininum<br> पुंस् | Neutrum<br> नपुंसक | | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | भरन्तौ | भरन्ती (!) | | तृतीया, चतुर्थी, पञ्चमी | भरद्भ्याम् | | सष्ठी, सप्तमी | भरतोस् |</p></blockquote><p><img src="'+o+'" alt=""><br> Abb.: भरन्तौ<br> [Bildquelle: Dey. -- <a href="http://www.flickr.com/photos/dey/459141804/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dey/459141804/</a>. -- Zugriff am 2009-01-19. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>ददत् 3 &quot;gebend&quot;</p><blockquote><p>|   | Maskulininum<br> पुंस् | Neutrum<br> नपुंसक | | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | ददतौ | ददती | | तृतीया, चतुर्थी, पञ्चमी | ददद्भ्याम् | | सष्ठी, सप्तमी | ददतोस् |</p></blockquote><p>Stämme auf -mant/-vant</p><p>पशुमन्त् 3 &quot;Vieh besitzend&quot;</p><blockquote><p>|   | Maskulininum<br> पुंस् | Neutrum<br> नपुंसक | | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | पशुमन्तौ | पशुमती | | तृतीया, चतुर्थी, पञ्चमी | पशुमद्भ्याम् | | सष्ठी, सप्तमी | पशुमतोस् |</p></blockquote><p>महान्त् 3 &quot;groß&quot;</p><blockquote><p>|   | Maskulininum<br> पुंस् | Neutrum<br> नपुंसक | | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | महान्तौ | महती | | तृतीया, चतुर्थी, पञ्चमी | महद्भ्याम् | | सष्ठी, सप्तमी | महतोस् |</p></blockquote><p>आत्मन् m.</p><blockquote><p>|   | Maskulininum<br> पुंस् | | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | आत्मानौ | | तृतीया, चतुर्थी, पञ्चमी | आत्मभ्याम् | | सष्ठी, सप्तमी | आत्मनोस् |</p></blockquote><p>ब्रह्मन् n.</p><blockquote><p>|   | Neutrum<br> नपुंसक | | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | ब्रह्मणी | | तृतीया, चतुर्थी, पञ्चमी | ब्रह्मभ्याम् | | सष्ठी, सप्तमी | ब्रह्मणोस् |</p></blockquote><p>राजन् m. &quot;König&quot;</p><blockquote><p>|   | Maskulininum<br> पुंस् | | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | राजानौ | | तृतीया, चतुर्थी, पञ्चमी | राजभ्याम् | | सष्ठी, सप्तमी | राज्ञोस् |</p></blockquote><p>सीमन् f. &quot;Grenze&quot;</p><blockquote><p>|   | Femininum<br> स्त्री | | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | सीमानौ | | तृतीया, चतुर्थी, पञ्चमी | सीमभ्याम् | | सष्ठी, सप्तमी | सीम्नोस् |</p></blockquote><p>नामन् n. &quot;Name&quot;</p><blockquote><p>|   | Neutrum<br> नपुंसक | | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | नाम्नी<br> नामानी | | तृतीया, चतुर्थी, पञ्चमी | नामभ्याम् | | सष्ठी, सप्तमी | नाम्नोस् |</p></blockquote><h2 id="_53-4-der-dual-vokalisch-auslautender-stamme" tabindex="-1">53.4. Der Dual vokalisch auslautender Stämme <a class="header-anchor" href="#_53-4-der-dual-vokalisch-auslautender-stamme" aria-label="Permalink to &quot;53.4. Der Dual vokalisch auslautender Stämme&quot;">​</a></h2><p>Stämme auf -a</p><p>देव m. &quot;Gott&quot;<br> फल n. &quot;Frucht</p><blockquote><p>|   | Maskulininum<br> पुंस् | Neutrum<br> नपुंसक | | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | देवौ | फले | | तृतीया, चतुर्थी, पञ्चमी | देवाभ्याम् | फलाभ्याम् | | सष्ठी, सप्तमी | देवयोस् | फलयोस् |</p></blockquote><p><img src="'+u+'" alt=""><br> Abb.: फले<br> मुंबई<br> [Bildquelle: gruntzooki. -- <a href="http://www.flickr.com/photos/doctorow/2890329486/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/doctorow/2890329486/</a>. -- Zugriff am 2009-01-19. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, share alike)]</p><p>Stämme auf -i</p><p>अग्नि m. &quot;Feuer&quot;<br> वारि n. &quot;Wasser&quot;<br> मति f. &quot;Gedanke&quot;</p><blockquote><p>|   | Maskulininum<br> पुंस् | Femininum<br> स्त्री | Neutrum<br> नपुंसक | | --- | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | अग्नी | मती | वारिणी | | तृतीया, चतुर्थी, पञ्चमी | अग्निभ्याम् | मतिभ्याम् | वारिभ्याम् | | सष्ठी, सप्तमी | अग्न्योस् | मत्योस् | वारिणोस् |</p></blockquote><p>Stämme auf -u</p><p>शत्रु m.<br> मधु n.<br> धेनु f.</p><blockquote><p>|   | Maskulininum<br> पुंस् | Femininum<br> स्त्री | Neutrum<br> नपुंसक | | --- | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | शत्रू | धेनू | मधुनी | | तृतीया, चतुर्थी, पञ्चमी | शत्रुभ्याम् | धेनुभ्याम् | मधुभ्याम् | | सष्ठी, सप्तमी | शत्र्वोस् | धेन्वोस् | मधुनोस् |</p></blockquote><p><img src="'+l+'" alt=""><br> Abb.: धेनू<br> Ahmedabad = અમદાવાદ<br> [Bildquelle: betta design. -- <a href="http://www.flickr.com/photos/betta_design/2742345344/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/betta_design/2742345344/</a>. -- Zugriff am 2009-01-19. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>Stämme auf -ā</p><p>कन्या f. &quot;Mädchen&quot;</p><blockquote><p>|   | Femininum<br> स्त्री | | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | कन्ये | | तृतीया, चतुर्थी, पञ्चमी | कन्याभ्याम् | | सष्ठी, सप्तमी | कन्ययोस् |</p></blockquote><p>Mehrsilbige Stämme auf -ī</p><p>देवी f. &quot;Göttin&quot;</p><blockquote><p>|   | Femininum<br> स्त्री | | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | देव्यौ | | तृतीया, चतुर्थी, पञ्चमी | देवीभ्याम् | | सष्ठी, सप्तमी | देव्योस् |</p></blockquote><p>Stämme auf -ṛ</p><p>दातृ 3 &quot;Geber&quot;</p><blockquote><p>|   | Maskulininum/Femininum<br> पुंस्/स्त्री | Neutrum<br> नपुंसक | | --- | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | दातरौ | दातृणी | | तृतीया, चतुर्थी, पञ्चमी | दातृभ्याम् | | सष्ठी, सप्तमी | दात्रोस् |</p></blockquote><p>पितृ m. &quot;Vater&quot;</p><blockquote><p>|   | Maskulininum<br> पुंस् | | --- | --- | | प्रथमा, द्वितीया, आमन्त्रितम् | पितरौ | | तृतीया, चतुर्थी, पञ्चमी | पितृभ्याम् | | सष्ठी, सप्तमी | पित्रोस् |</p></blockquote><h2 id="_53-5-dualdvandva" tabindex="-1">53.5. Dualdvandva <a class="header-anchor" href="#_53-5-dualdvandva" aria-label="Permalink to &quot;53.5. Dualdvandva&quot;">​</a></h2><p>Beispiele:</p><blockquote><p>अर्थधर्मौ &quot;Nutzen (अर्थ) und Dharma&quot;<br> युधिष्ठिरार्जुनौ &quot;Yudhiṣṭhira und Arjuna&quot;<br> सुखदुःखे (neben: सुखदुःखम्) &quot;Glück und Leid&quot;<br> शीतोष्णे &quot;Kälte und Wärme&quot;</p></blockquote><p>Werden zwei Verwandtschaftswörter auf -ṛ (oder zwei Substantive auf -ṛ, die Bezeichnungen für Opferpriester sind) zu einem Dvandva komponiert, so steht das erste Glied in der Form des Nominativ Singular:</p><blockquote><p>मतापितरौ &quot;Mutter und Vater&quot;</p></blockquote><p>Dasselbe geschieht mit einem solchen Verwandtschaftswort in einem Dvandva vor -पुत्र :</p><blockquote><p>पितापुत्रौ &quot;Vater und Sohn&quot;</p></blockquote><p>Bilden die Namen zweier Gottheiten, die gewöhnlich bei Opfern genannt werden, ein Dvandva, so wird der auslautende Vokal des ersten Gliedes gewöhnlich verlängert:</p><blockquote><p>मित्रावरुणौ &quot;Mitra und Varuṇa&quot;<br> अग्नीसोमौ &quot;Agni und Soma&quot;</p></blockquote><p>Auch bei anderen Dvandva kommt diese Vokalverlängerung vor.</p><p><img src="'+s+'" alt=""><br> Abb.: पितापुत्रौ<br> [Bildquelle: Dey. -- <a href="http://www.flickr.com/photos/dey/458678074/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dey/458678074/</a>. -- Zugriff am 2009-01-19. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><h2 id="_53-6-der-dual-von-pronomina" tabindex="-1">53.6. Der Dual von Pronomina <a class="header-anchor" href="#_53-6-der-dual-von-pronomina" aria-label="Permalink to &quot;53.6. Der Dual von Pronomina&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>तद्</th><th>एतद्</th><th>इदम्</th><th>यद्</th><th>किम्</th></tr></thead><tbody><tr><td>Maskulinum</td><td></td><td></td><td></td><td></td><td></td></tr><tr><td>प्रथमा</td><td>तौ</td><td>एतौ</td><td>इमौ</td><td>यौ</td><td>कौ</td></tr><tr><td>द्वितीया</td><td>तौ</td><td>एतौ</td><td></td><td></td><td></td></tr><tr><td>एनौ</td><td>इमौ</td><td></td><td></td><td></td><td></td></tr><tr><td>एनौ</td><td>यौ</td><td>कौ</td><td></td><td></td><td></td></tr><tr><td>तृतीया, चतुर्थी, पञ्चमी</td><td>ताभ्याम्</td><td>एताभ्याम्</td><td>आभ्याम्</td><td>याभ्याम्</td><td>काभ्याम्</td></tr><tr><td>षष्ठी, सप्तमी</td><td>तयोस्</td><td>एतयोस्</td><td></td><td></td><td></td></tr><tr><td>एनयोस्</td><td>अनयोस्</td><td></td><td></td><td></td><td></td></tr><tr><td>एनयोस्</td><td>ययोस्</td><td>कयोस्</td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td><td></td></tr><tr><td>Neutrum</td><td></td><td></td><td></td><td></td><td></td></tr><tr><td>प्रथमा</td><td>ते</td><td>एते</td><td>इमे</td><td>ये</td><td>के</td></tr><tr><td>द्वितीया</td><td>ते</td><td>एते</td><td></td><td></td><td></td></tr><tr><td>एने</td><td>इमे</td><td></td><td></td><td></td><td></td></tr><tr><td>एने</td><td>ये</td><td>के</td><td></td><td></td><td></td></tr><tr><td></td><td>Rest wie Maskulinum</td><td></td><td></td><td></td><td></td></tr><tr><td>Femininum</td><td></td><td></td><td></td><td></td><td></td></tr><tr><td>प्रथमा</td><td>ते</td><td>एते</td><td>इमे</td><td>ये</td><td>के</td></tr><tr><td>द्वितीया</td><td>ते</td><td>एते</td><td></td><td></td><td></td></tr><tr><td>एने</td><td>इमे</td><td></td><td></td><td></td><td></td></tr><tr><td>एने</td><td>ये</td><td>के</td><td></td><td></td><td></td></tr><tr><td></td><td>Rest wie Maskulinum</td><td></td><td></td><td></td><td></td></tr></tbody></table><p>कतर 3 &quot;wer von beiden&quot; und कतम 3 &quot;wer von mehreren&quot; werden in allen Kasus wie यद् dekliniert.</p><h2 id="_53-7-pronominaladjektive" tabindex="-1">53.7. Pronominaladjektive <a class="header-anchor" href="#_53-7-pronominaladjektive" aria-label="Permalink to &quot;53.7. Pronominaladjektive&quot;">​</a></h2><p>Folgende Pronominaladjektive werden in allen Kasus wie यद् dekliniert:</p><ul><li><p>अन्य 3 &quot;ein anderer&quot;</p></li><li><p>अन्यतर 3 &quot;einer von zweien&quot;</p></li><li><p>इतर 3 &quot;der andere&quot;</p></li><li><p>सर्व 3 &quot;jeder, alle&quot; wird in allen Kasus außer dem Nom.Akk.sg.n (सर्वम्) wie यद् dekliniert.</p></li><li><p>उभय 3 &quot;beide&quot; hat keinen Dual. Im Singular und Plural mask. und neutr. wird es wie सर्व dekliniert. Femininum: उभयी (wie देवी).</p></li><li><p>उभ 3 &quot;beide&quot; wird nur im Dual gebraucht und wird wie देव m., फल n. bzw. देवता f. dekliniert.</p></li></ul><p>Folgende Pronominaladjektive werden wie सर्व dekliniert. Im Abl.Lok.sg.m.n sowie in im Nom.pl. können sie nach der -a- bzw. -ā-Deklination dekliniert werden:</p><ul><li>अपर 3 &quot;ein anderer&quot;</li><li>उत्तर 3 &quot;der obere, nördliche, nachfolgende&quot;</li><li>पर 3 &quot;der folgende, spätere&quot;</li><li>पूर्व 3 &quot;der vorausgehende, östliche&quot;</li><li>स्व 3 &quot;eigen (mein, dein, sein ...)&quot;</li></ul><h2 id="_53-8-unregelmaßige-steigerung" tabindex="-1">53.8. Unregelmäßige Steigerung <a class="header-anchor" href="#_53-8-unregelmaßige-steigerung" aria-label="Permalink to &quot;53.8. Unregelmäßige Steigerung&quot;">​</a></h2><p>Eine Anzahl von Adjektiven bildet den Komparativ bzw. Superlativ mit folgenden कृत्-Suffixen (!):</p><ul><li>Komparativ: -īyas</li><li>Superlativ: -ṣṭha</li></ul><p>Während die तद्धित-Suffixe -तर und -तम an den Maskulinstamm des Adjektivs treten, werden die Suffixe -ईयस् und -इष्ठ an die Wurzel angefügt, von der das Adjektiv abgeleitet ist (sofern es eine solche Wurzel gibt!). Der Wurzelvokal ist hochstufig.</p><p>Superlative auf -iṣṭha (Fem.: iṣṭhā) werden  wie a- bzw. ā-Stämme dekliniert.</p><p>Deklonation von -īyas siehe unten.</p><p>Beispiele:</p><table tabindex="0"><thead><tr><th>Wurzel</th><th>Adjektiv</th><th>Komparativ</th><th>Superlativ</th></tr></thead><tbody><tr><td>क्षिप् 6P &quot;werfen&quot;</td><td>क्षिप्र 3 &quot;schnell</td><td>क्षेपीयस् 3 &quot;schneller&quot;</td><td></td></tr><tr><td>क्षिप्रतर 3</td><td>क्षेपिष्ठ 3 &quot;am schnellsten&quot;</td><td></td><td></td></tr><tr><td>क्षिप्रतम 3</td><td></td><td></td><td></td></tr><tr><td>स्था 1P &quot;stehen&quot;</td><td>स्थिर 3 &quot;beständig, fest&quot;</td><td>स्थेयस् 3 &quot;fester&quot;</td><td></td></tr><tr><td>स्थिरतर 3</td><td>स्थेष्ठ 3 &quot;am festesten&quot;</td><td></td><td></td></tr><tr><td>स्थिरतम 3</td><td></td><td></td><td></td></tr></tbody></table><p>Besondere Regeln für die Anfügung dieser Suffixe:</p><p>Regel 1: Der auslautende Vokal eines mehrsilbigen Maskulinstammes oder der auslautende Vokal und der vorausgehende Vokal fallen ab.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Adjektiv</th><th>Komparativ</th><th>Superlativ</th></tr></thead><tbody><tr><td>पाप 3 &quot;böse&quot;</td><td>पापीयस्</td><td>पापिष्ठ</td></tr><tr><td>महान्त् 3 &quot;groß&quot;</td><td>महीयस्</td><td>महिष्ठ</td></tr></tbody></table></blockquote><p>Regel 2: Possessivsuffixe (-mant, vant, -vin, -in u.ä.) fallen ab. Besteht der übrig bleibende Teil nur aus einer Silbe, wird er nicht weiter verändert, nur durch die Verbindung mit dem Possesivsuffix bedingte Lautveränderungen werden rückgängig gemacht. Besteht der Rest aber aus mehr als einer Silbe, tritt Regel 1 in Kraft.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Adjektiv</th><th>Komparativ</th><th>Superlativ</th></tr></thead><tbody><tr><td>धनवन्त् 3 &quot;reich&quot;</td><td>धनीयस्</td><td>धनिष्ठ</td></tr><tr><td>बलिन् 3 &quot;(besonders) stark&quot;</td><td>बलीयस्</td><td>बलिष्ठ</td></tr><tr><td>वसुमन्त् &quot;Güter besitzend&quot;</td><td>वसीयस्</td><td>वसिष्ठ</td></tr></tbody></table></blockquote><p>Regel 3: Für -ṛ-, dem ein Anfangsvokal vorausgeht und auf das nur ein einziger Konsonant folgt, wird -ra- substituiert.</p><p>Beispiel:</p><blockquote><table tabindex="0"><thead><tr><th>Adjektiv</th><th>Komparativ</th><th>Superlativ</th></tr></thead><tbody><tr><td>पृथु 3 &quot;breit&quot;</td><td>प्रथीयस्</td><td>प्रथिष्ठ</td></tr></tbody></table></blockquote><p>Verzeichnis der häufigsten Steigerungsformen solcher Art zu bisher gelernten Adjektiven:</p><blockquote><table tabindex="0"><thead><tr><th>Adjektiv</th><th>Komparativ</th><th>Superlativ</th></tr></thead><tbody><tr><td>अल्प 3 &quot;klein, wenig&quot;</td><td>अल्पीयस्</td><td>अल्पिष्ठ</td></tr><tr><td>क्षिप्र 3 &quot;schnell&quot;</td><td></td><td></td></tr><tr><td>(zu क्षिप्)</td><td>क्षेपीयस्</td><td>क्षेपिष्ठ</td></tr><tr><td>गुरु 3 &quot;schwer&quot;</td><td></td><td></td></tr><tr><td>(zu *गृ)</td><td>गरीयस्</td><td>गरिष्ठ</td></tr><tr><td>दीर्घ 3 &quot;lang&quot;</td><td></td><td></td></tr><tr><td>(zu *दृघ्)</td><td>द्राघीयस्</td><td>द्राघिष्ठ</td></tr><tr><td>दूर 3 &quot;fern&quot;</td><td></td><td></td></tr><tr><td>(zu *दु/*दू)</td><td>दवीयस्</td><td>दविष्ठ</td></tr><tr><td>धनवन्त् 3 &quot;reich&quot;</td><td>धनीयस्</td><td>धनिष्ठ</td></tr><tr><td>पाप 3 &quot;böse&quot;</td><td>पापीयस्</td><td>पापिष्ठ</td></tr><tr><td>पृथु 3 &quot;breit&quot;</td><td>प्रथीयस्</td><td>प्रथीष्ठ</td></tr><tr><td>प्रिय 3 &quot;lieb&quot;</td><td>प्रेयस्</td><td>प्रेष्ठ</td></tr><tr><td>बलिन् 3 &quot;(besonders) stark&quot;</td><td>बलीयस्</td><td>बलिष्ठ</td></tr><tr><td>महान्त् 3 &quot;groß&quot;</td><td>महीयस्</td><td>महिष्ठ</td></tr><tr><td>युवन् 3 &quot;jung&quot;</td><td>यवीयस्</td><td>यविष्ठ</td></tr><tr><td>स्थिर 3 &quot;fest&quot;</td><td></td><td></td></tr><tr><td>(zu स्था)</td><td>स्थेयस्</td><td>स्थेष्ठ</td></tr><tr><td>ह्रस्व 3 &quot;kurz&quot;</td><td>ह्रसीयस्</td><td>ह्रसिष्ठ</td></tr></tbody></table></blockquote><p><img src="'+m+'" alt=""><br> Abb.: द्राघीयो लिङ्गम् : लोकस्य द्राघिष्ठं शिवलिङ्गम्<br> 33 m hoch<br> Kotilingeshwara-Temple, Kamamsandra, Kolar-District = ಕೋಲಾರ, Karnataka = ಕರ್ನಾಟಕ<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/150301623/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/150301623/</a>. -- Zugriff am 2009-01-19. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>Einige Steigerungsformen dieser Art haben überhaupt keine wurzelverwandte Grundform, sie sind &quot;defektiv&quot;. Deshalb sind folgende Reihen besonders zu merken:</p><blockquote><table tabindex="0"><thead><tr><th>(Adjektiv)</th><th>Komparativ</th><th>Superlativ</th></tr></thead><tbody><tr><td>(अल्प 3 &quot;klein, wenig&quot;)</td><td>कनीयस्</td><td></td></tr><tr><td>vgl.  कन्या f. &quot;Mädchen = die Kleine&quot;</td><td>कनिष्ठ</td><td></td></tr><tr><td>(प्रशस्य 3 &quot;lobenswert, gut&quot;)</td><td>श्रेयस्</td><td></td></tr><tr><td>zu श्री f. &quot;Glanz&quot;</td><td>श्रेष्ठ</td><td></td></tr><tr><td>(प्रशस्य 3 &quot;lobenswert, gut&quot;)</td><td>ज्यायस्</td><td></td></tr><tr><td>auch: &quot;älter&quot;</td><td></td><td></td></tr><tr><td>zu ज्या f. &quot;Übergewalt&quot;</td><td>ज्येष्ठ</td><td></td></tr><tr><td>auch: &quot;am ältesten&quot;</td><td></td><td></td></tr><tr><td>(बहु 3 &quot;viel&quot;)</td><td>भूयस्</td><td>भूयिष्ठ</td></tr><tr><td>(वृद्ध 3 &quot;alt&quot;)</td><td>वर्षीयस्</td><td></td></tr><tr><td>zu वर्ष n.m. &quot;Regenzeit, Jahr&quot;</td><td>वर्षिष्ठ</td><td></td></tr><tr><td>(वृद्ध 3 &quot;alt&quot;)</td><td>ज्यायस्</td><td></td></tr><tr><td>auch: &quot;besser&quot;</td><td></td><td></td></tr><tr><td>zu ज्या f. &quot;Übergewalt&quot;</td><td>ज्येष्ठ</td><td></td></tr><tr><td>auch: &quot;bester&quot;</td><td></td><td></td></tr></tbody></table></blockquote><h2 id="_53-9-deklination-der-komparative-auf-iyas" tabindex="-1">53.9. Deklination der Komparative auf -īyas <a class="header-anchor" href="#_53-9-deklination-der-komparative-auf-iyas" aria-label="Permalink to &quot;53.9. Deklination der Komparative auf -īyas&quot;">​</a></h2><p>Komparative auf -īyas bilden das Femininum auf -īyasī (Deklination wie देवी). Das maskulinum und Neutrum wird nach folgendem Paradigma dekliniert.</p><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>द्विवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td></td><td>पुमान्</td><td>नपुंसकम्</td><td>पुमान्</td></tr><tr><td>प्रथमा</td><td>गरीयान्</td><td>गरीयस्</td><td>गरीयांसौ</td></tr><tr><td>द्वितीया</td><td>गरीयांसम्</td><td>गरीयस्</td><td>गरीयसस्</td></tr><tr><td>तृतीया</td><td>गरीयसा</td><td>गरीयोभ्याम्</td><td>गरीयोभिस्</td></tr><tr><td>चतुर्थी</td><td>गरीयसे</td><td>गरीयोभ्यस्</td><td></td></tr><tr><td>पञ्चमी</td><td>गरीयसस्</td><td></td><td></td></tr><tr><td>षष्ठी</td><td>गरीयसस्</td><td>गरीयसोस्</td><td>गरीयसाम्</td></tr><tr><td>सप्तमी</td><td>गरीयसि</td><td>गरीयःसु</td><td></td></tr><tr><td>गरीयस्सु</td><td></td><td></td><td></td></tr><tr><td>आमन्त्रितम्</td><td>गरीयान्</td><td>गरीयस्</td><td>गरियांसौ</td></tr></tbody></table><h2 id="_53-10-metrik-lehre-von-den-versmaßen" tabindex="-1">53.10. Metrik (Lehre von den Versmaßen) <a class="header-anchor" href="#_53-10-metrik-lehre-von-den-versmaßen" aria-label="Permalink to &quot;53.10. Metrik (Lehre von den Versmaßen)&quot;">​</a></h2><p><img src="'+p+'" alt=""><br> Abb.: Christian Morgenstern &lt;1871 - 1914&gt;: Fisches Nachtgesang: das tiefste deutsche Gedicht</p><p>Siehe auch:</p><blockquote><p>Payer, Alois &lt;1944 - &gt;: Einführung in die Exegese von Sanskrittexten : Skript.  -- Kap. 8: Die eigentliche Exegese, Teil II: Zu einzelnen Fragestellungen synchronen Verstehens. -- Anhang B: Zur Metrik von Sanskrittexten. -- URL: <a href="http://www.payer.de/exegese/exeg08b.htm" target="_blank" rel="noreferrer">http://www.payer.de/exegese/exeg08b.htm</a></p></blockquote><h3 id="_53-10-1-bedeutung-der-bestimmung-des-metrums" tabindex="-1">53.10.1. Bedeutung der Bestimmung des Metrums <a class="header-anchor" href="#_53-10-1-bedeutung-der-bestimmung-des-metrums" aria-label="Permalink to &quot;53.10.1. Bedeutung der Bestimmung des Metrums&quot;">​</a></h3><p>Die Bestimmung des Metrums ist aus folgenden Gründen wichtig:</p><ol><li><p>Ästhetisch: das Versmaß macht u.a. die Schönheit einer Aussage aus. Auch dienen bestimmte Versmaße u.U. dazu, bestimmte Stimmungen auszudrücken, oder sie sind bestimmten Ständen (वर्ण) zugeordnet. Die verschiedenen Versmaße werden je verschieden rezitiert.</p><p>Einen guten Eindruck der ästhetischen Wirkung gibt z.B. die Rezitation des शिवताण्डवस्तोत्र (Lobpreis des Tanzes Śivas): <a href="http://de.youtube.com/watch?v=5KjfiJlkO58" target="_blank" rel="noreferrer">http://de.youtube.com/watch?v=5KjfiJlkO58</a></p></li><li><p>Textkritisch: Fehler im Versmaß können ein Hinweis darauf sein, dass der Text an einer Stelle nicht korrekt überliefert ist. Das Versmaß hilft, Textverbesserungen vorzunehmen.</p></li><li><p>Chronologisch: gewisse Versmaße gingen im Lauf der Geschichte bestimmte Veränderungen durch. Das kann bei der ungefähren Datierung eines Textes helfen. Siehe dazu Oldenberg, Hermann &lt;1854 - 1920&gt;: Zur Geschichte der Triṣṭhubh ; ders.: Zur Geschichte des Śloka. -- Beides abgedruckt in:<br> Oldenberg, Hermann &lt;1854 - 1920&gt;:Kleine Schriften / Hermann Oldenberg. Hrsg. von Klaus L. Janert. -- Wiesbaden : Steiner. -- 3 Bde. -- (Glasenapp-Stiftung ; ...). -- Bd. 2. -- 1967. -- S. 1188 - 1255.</p></li></ol><p><img src="'+b+'" alt=""><br> Abb.: Herrmann Oldenberg (1854 - 1920)<br> 1889 bis 1908 Ordinarius für Sanskrit in Kiel, von 1908 bis 1920 in Göttingen<br> [Bildquelle: Wikipedia. Public domain]</p><h3 id="_53-10-2-arten-von-metren" tabindex="-1">53.10.2. Arten von Metren <a class="header-anchor" href="#_53-10-2-arten-von-metren" aria-label="Permalink to &quot;53.10.2. Arten von Metren&quot;">​</a></h3><p>Die Inder unterscheiden:</p><ul><li>वृत्त n.: Metren, bei denen die Zahl der Silben (अक्षर) festgelegt ist</li><li>जाति f.: Metren, bei denen die Summe der metrischen Längeneinheiten (मात्रा) (Moren) festgelegt ist (zu diesen später)</li></ul><p>Bei den Metren, bei denen die Zahl der Silben festgelegt ist (वृत्त) kann man zunächst weiter unterscheiden:</p><ul><li>Metren, bei denen die Zahl der Silben festgelegt ist, die Quantität dieser Silben aber nur teilweise</li><li>Metren, bei denen die Zahl der Silben und deren Quantität festgelegt ist</li></ul><h3 id="_53-10-3-die-metrische-quantitat-von-silben" tabindex="-1">53.10.3. Die metrische Quantität von Silben <a class="header-anchor" href="#_53-10-3-die-metrische-quantitat-von-silben" aria-label="Permalink to &quot;53.10.3. Die metrische Quantität von Silben&quot;">​</a></h3><p>Merkvers</p><blockquote><p>सानुस्वारश्च दीर्घश्च<br> विसर्गी च गुरुर् भवेत् ।<br> वर्णः संयोगपूर्वश्च<br> तथा पादान्तगो ऽपि वा ॥</p><p>&quot;Eine Silber ist schwer,</p><ul><li><p>wenn ihr Vokal einen Anusvāra hat,</p></li><li><p>lang ist,</p></li><li><p>einen Visarga hat,</p></li><li><p>ebenso wenn er vor einer Konsonantenverbindung steht</p></li><li><p>sowie wenn die Silbe am Schluss eines Viertelverses (Pāda) steht.&quot;</p></li></ul></blockquote><p>Eine Silbe ist</p><ul><li>entweder लघु = leicht</li><li>oder गुरु = schwer</li></ul><p>लघु = leicht ist eine Silbe, wenn</p><ul><li>ihr Vokal kurz ist und auf diesen Vokal</li><li>kein Anusvāra,</li><li>kein Visarga,</li><li>nicht zwei Konsonanten folgen.</li></ul><p>Kurze Vokale sind a, i, u, ṛ, ḷ</p><p>Alle anderen Silben sind गुरु = schwer. Die letzte Silbe eines Versviertels (पाद) gilt immer als गुरु.</p><p>In der metrischen Analyse bedeutet:</p><ul><li><p>˘ = ल = लघु</p></li><li><p>ˉ = ग = गुरु</p></li><li><p>̽ = लघु oder गुरु</p></li><li><p>/ = Zäsur (Worttrennung)</p></li></ul><p>Beispiel: भगवद्गीता १,१:</p><blockquote><p>धर्मक्षेत्रे कुरुक्षेत्रे समवेता युयुत्सवः ।<br> मामकाः पाण्डवाश्चैव किं अकुर्वत संजय ॥१॥</p><p>Verteilung von लघु und गुरु :</p><p>ˉˉˉˉ˘ˉˉˉ ˘˘ˉˉ˘ˉ˘ˉ<br> ˉ˘ˉˉ˘ˉˉˉ ˘˘ˉ˘˘ˉ˘ˉ</p></blockquote><h3 id="_53-10-4-der-epische-sloka-श्लोक-m" tabindex="-1">53.10.4. Der epische Śloka (श्लोक m.) <a class="header-anchor" href="#_53-10-4-der-epische-sloka-श्लोक-m" aria-label="Permalink to &quot;53.10.4. Der epische Śloka (श्लोक m.)&quot;">​</a></h3><p>Merkvers:</p><p>श्लोके षष्ठं गुरु ज्ञेयं<br> सर्वत्र लघु पञ्चमम् ।<br> द्विचतुष्पादयोर्ह्रस्वं<br> सप्तमं दीर्घमन्ययोः ॥</p><blockquote><p>&quot;Im Śloka ist die sechste Silbe eines Pāda schwer,<br> die fünfte in allen Pādas leicht<br> Die siebte Silbe ist im zweiten und vierten Pāda kurz, lang in den beiden anderen.&quot;</p></blockquote><p>Das wichtigste Versmaß in den Epen (महाभारत, रामायण) sowie unzähligen anderen Werken ist der Śloka (&quot;Ruf&quot;, &quot;Geräusch&quot;, &quot;Strophe&quot; zu श्रु &quot;hören&quot;).</p><p>Der श्लोक ist eine Doppelvers aus Halbversen zu je 16 Silben. Jeder Halbvers zerfällt wieder in zwei Viertelverse (पाद) zu je 8 Silben. Jeder Viertelvers zerfällt in zwei Teile zu je 4 Silben. Der ganze Vers (पद्य n.) besteht also aus vier पाद (m. &quot;Fuß, Viertel&quot;). Die vier पाद werden mit a, b, c, (क्, ख्, ग्, घ्) durchgezählt.</p><p>Aufbau des Śloka:</p><p>Grundschema (पथ्या):</p><blockquote><p>a = c:</p><p>̽ ̽ ̽ ̽ ˘ˉˉˉ</p><p>b = d:</p><p>̽ ̽ ̽ ̽ ˘ˉ˘ˉ</p></blockquote><p>Die zweite und dritte Silbe eines पाद sollten nicht zugleich लघु sein. In b und d darf Silbe 2 - 4 nicht ˉ˘ˉsein.</p><p>Nebenschemata (विपुला) für a und c:</p><p>विपुला 1:</p><blockquote><p>̽ ̽ ̽ ˉ ˘˘˘ˉ</p></blockquote><p>विपुला 2:</p><blockquote><p>̽ ˉ˘ˉ ˉ˘˘ˉ</p></blockquote><p>विपुला 3:</p><blockquote><p>̽ ˉ˘ˉˉ/ˉˉˉ</p></blockquote><p>विपुला 4:</p><blockquote><p>̽ ̽ ̽ ̽ / ˉ˘ˉˉ</p></blockquote><p>Bei allen Ślokaformen liegt die Hauptzäsur am Ende des 2. पाद : dort ist entweder Wortende oder - bei langen Komposita - Ende eines Kompositionsgliedes.</p><h2 id="_53-11-ubung" tabindex="-1">53.11. Übung <a class="header-anchor" href="#_53-11-ubung" aria-label="Permalink to &quot;53.11. Übung&quot;">​</a></h2><p>Bestimmen sie unter allen bisher gelernten Versen die Ślokas. Machen Sie zu diesen schriftlich das metrische Schema. Weisen Sie auf eventuelle Unregelmäßigkeiten bzw. Vipulāformen hin.</p><p>Finitum feliciter 1984-02-15<br> Editio interretialis feliciter finita 2009-01-19</p><p>Alois Maria Payer</p><p>श्रीगणेषाय नमः</p>',172)])])}const S=e(h,[["render",c]]);export{z as __pageData,S as default};
